// <auto-generated>
// Rust port of DBPersist.core.cs.
//
// Static helper surface for persistence. insert/update normally dispatch to
// the audit or basic strategy based on `is_audited`; put/get and the SQL
// builders are shared. Reflection over ColumnInfoAttribute is replaced by the
// generated `T::columns()` metadata. Values are rendered as escaped SQL
// literals (the same approach the .NET update/filter path used), which
// round-trips the string-backed temporal/decimal/uuid values correctly.
//
// Import mode: the `import` tool loads data files that already carry real pk
// values, and those values must survive the insert instead of being
// overwritten by a freshly generated identity. Rather than plumb a provider
// choice through every call site (LogicContext, the generated per-object
// insert/update, etc.), the import binary flips a process-wide flag once at
// startup via `DBPersist::set_import_mode(true)`. While set, insert/update
// use the `Import` strategy unconditionally — ahead of the audited/basic
// check — regardless of the domain object's `is_audited` flag. No other
// generated binary (api, scheduler, scriptagent, export) ever calls the
// setter, so the flag is always false there and behavior is unchanged.
// </auto-generated>

use std::collections::HashMap;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Mutex, OnceLock};

use common::{BaseObject, DatabaseProviderFactory, DomainObject, Logger};
use serde_json::Value;

use crate::db_connection::{DbConnection, PersistError, Row};
use crate::{db_persist_audit, db_persist_basic, db_persist_import};

/// Process-wide switch to the `Import` persist strategy. Set once by the
/// import tool's `main()`; left false everywhere else.
static IMPORT_MODE: AtomicBool = AtomicBool::new(false);

fn query_cache() -> &'static Mutex<HashMap<String, Option<BaseObject>>> {
    static CACHE: OnceLock<Mutex<HashMap<String, Option<BaseObject>>>> = OnceLock::new();
    CACHE.get_or_init(|| Mutex::new(HashMap::new()))
}

pub struct DBPersist;

impl DBPersist {
    // ── SELECT ──────────────────────────────────────────────────────────

    pub fn select(sql: &str, connection_name: &str) -> Result<Vec<Row>, PersistError> {
        Logger::debug(format!("Executing sql {} on connection '{}'.", sql, connection_name));
        let mut conn = DbConnection::open(connection_name)?;
        conn.query(sql)
    }

    pub fn select_template(
        sql_template: &str,
        filter: &BaseObject,
        connection_name: &str,
    ) -> Result<Vec<Row>, PersistError> {
        let sql = Self::substitute_template(filter, sql_template);
        Self::select(&sql, connection_name)
    }

    /// Generic select: materialise each row into a domain object.
    pub fn select_into<T: DomainObject + Default>(
        sql: &str,
        connection_name: &str,
    ) -> Result<Vec<T>, PersistError> {
        let rows = Self::select(sql, connection_name)?;
        Ok(rows
            .into_iter()
            .map(|row| {
                let mut obj = T::default();
                obj.initialize();
                Self::auto_assign(&row, &mut obj);
                obj
            })
            .collect())
    }

    // ── INSERT / UPDATE / PUT / GET (dispatch on import mode / is_audited) ─

    /// Switch the process to (or off) the `Import` persist strategy. The
    /// import tool calls this once, at startup, with `true`; nothing else
    /// should call it.
    pub fn set_import_mode(enabled: bool) {
        IMPORT_MODE.store(enabled, Ordering::SeqCst);
    }

    pub fn is_import_mode() -> bool {
        IMPORT_MODE.load(Ordering::SeqCst)
    }

    pub fn insert<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<i64, PersistError> {
        if Self::is_import_mode() {
            db_persist_import::insert(obj, connection_name)
        } else if obj.base().is_audited {
            db_persist_audit::insert(obj, connection_name)
        } else {
            db_persist_basic::insert(obj, connection_name)
        }
    }

    pub fn update<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<(), PersistError> {
        if Self::is_import_mode() {
            db_persist_import::update(obj, connection_name)
        } else if obj.base().is_audited {
            db_persist_audit::update(obj, connection_name)
        } else {
            db_persist_basic::update(obj, connection_name)
        }
    }

    /// Filter-based bulk update — in-place, no new version row (shared).
    pub fn update_filtered<T: DomainObject>(
        obj: &mut T,
        filter: &BaseObject,
        connection_name: &str,
    ) -> Result<(), PersistError> {
        obj.base_mut().set("last_updated", json_now());
        obj.base_mut().set("last_updated_by", Value::String(user_name()));
        let sql = Self::update_sql_filtered(obj.base(), filter, connection_name);
        Self::exec_cmd(&sql, connection_name)?;
        Ok(())
    }

    /// Upsert by a single real-world-key column.
    pub fn put_by<T: DomainObject>(
        obj: &mut T,
        rwk_col: &str,
        connection_name: &str,
    ) -> Result<(), PersistError> {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let sql = format!(
            "select * from {} where {} = {} and is_active=1",
            provider.format_table_name(&obj.base().table_name),
            provider.format_column_name(rwk_col),
            provider.format_value(&obj.base().get(rwk_col)),
        );

        let rows = Self::select(&sql, connection_name)?;
        if let Some(row) = rows.first() {
            if let Some(id) = row.get("id") {
                obj.base_mut().set("id", id.clone());
            }
            Self::update(obj, connection_name)
        } else {
            Self::insert(obj, connection_name).map(|_| ())
        }
    }

    /// Upsert by id (if set) or by the object's full rwk list.
    pub fn put<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<(), PersistError> {
        let provider = DatabaseProviderFactory::create_provider(connection_name);

        let has_id = obj.base().get("id").as_i64().unwrap_or_default() != 0;
        let mut count = 0;

        if !has_id {
            let rwk = obj.base().get_rwk().to_vec();
            if rwk.is_empty() {
                return Err(PersistError::Db(format!(
                    "{}.rwk is empty; put() needs at least one rwk attribute.",
                    obj.base().domain_name
                )));
            }
            let expression = Self::expr_sql(obj.base(), &rwk, " and ", connection_name);
            let sql = format!(
                "select * from {} where {} and is_active=1",
                provider.format_table_name(&format!(
                    "{}.{}",
                    obj.base().schema_name,
                    obj.base().table_base_name
                )),
                expression,
            );
            let rows = Self::select(&sql, connection_name)?;
            count = rows.len();
            if let Some(row) = rows.first() {
                if let Some(id) = row.get("id") {
                    obj.base_mut().set("id", id.clone());
                }
            }
        }

        if count == 1 || has_id {
            Self::update(obj, connection_name)
        } else if count == 0 {
            Self::insert(obj, connection_name).map(|_| ())
        } else {
            Err(PersistError::Db(format!(
                "{}.rwk returned more than one row.",
                obj.base().domain_name
            )))
        }
    }

    /// Load a single row by the object's id into `obj`.
    pub fn get<T: DomainObject>(obj: &mut T, connection_name: &str) -> Result<(), PersistError> {
        let sql = Self::get_sql(obj.base(), connection_name);
        let rows = Self::select(&sql, connection_name)?;
        if let Some(row) = rows.first() {
            Self::auto_assign(row, obj);
        }
        Ok(())
    }

    /// Construct a domain object and load it by id.
    pub fn get_by_id<T: DomainObject + Default>(
        id: i64,
        connection_name: &str,
    ) -> Result<T, PersistError> {
        let mut obj = T::default();
        obj.initialize();
        obj.base_mut().set("id", Value::from(id));
        Self::get(&mut obj, connection_name)?;
        Ok(obj)
    }

    // ── EXEC CMD ─────────────────────────────────────────────────────────

    pub fn exec_cmd(sql: &str, connection_name: &str) -> Result<u64, PersistError> {
        Logger::debug(format!("Executing sql {} on connection '{}'.", sql, connection_name));
        match DbConnection::open(connection_name).and_then(|mut c| c.execute(sql)) {
            Ok(n) => Ok(n),
            Err(e) => {
                Logger::error(format!("{}: {} on connection '{}'", e, sql, connection_name));
                Err(e)
            }
        }
    }

    pub fn exec_cmd_template(
        params: &BaseObject,
        sql_template: &str,
        connection_name: &str,
    ) -> Result<u64, PersistError> {
        let sql = Self::substitute_template(params, sql_template);
        Self::exec_cmd(&sql, connection_name)
    }

    // ── SQL BUILDERS ─────────────────────────────────────────────────────

    /// Build a literal INSERT over the type's declared columns.
    pub fn insert_sql<T: DomainObject>(obj: &T, table_name: &str, connection_name: &str) -> String {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let mut cols = Vec::new();
        let mut vals = Vec::new();
        for col in T::columns() {
            cols.push(provider.format_column_name(col.name));
            vals.push(provider.format_value(&obj.base().get(col.name)));
        }
        format!(
            "insert into {} ({}) values ({});",
            provider.format_table_name(table_name),
            cols.join(","),
            vals.join(",")
        )
    }

    pub fn update_sql(base: &BaseObject, connection_name: &str) -> String {
        let mut filter = BaseObject::new();
        filter.set("id", base.get("id"));
        Self::update_sql_filtered(base, &filter, connection_name)
    }

    pub fn update_sql_filtered(base: &BaseObject, filter: &BaseObject, connection_name: &str) -> String {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let set_keys: Vec<String> = base.data.keys().cloned().collect();
        let where_keys: Vec<String> = filter.data.keys().cloned().collect();
        let expressions = Self::expr_sql(base, &set_keys, ", ", connection_name);
        let where_clause = Self::expr_sql(filter, &where_keys, " and ", connection_name);
        format!(
            "update {} set {} where {};",
            provider.format_table_name(&base.table_name),
            expressions,
            where_clause
        )
    }

    /// Build `col=value` expressions for the given keys, skipping empties.
    pub fn expr_sql(
        base: &BaseObject,
        keys: &[String],
        sep_token: &str,
        connection_name: &str,
    ) -> String {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let mut parts = Vec::new();
        for k in keys {
            let v = base.get(k);
            if v.is_null() {
                continue;
            }
            if let Value::String(s) = &v {
                if s.is_empty() {
                    continue;
                }
            }
            parts.push(format!(
                "{}={}",
                provider.format_column_name(k),
                provider.format_value(&v)
            ));
        }
        parts.join(sep_token)
    }

    pub fn identity(base: &BaseObject, connection_name: &str) -> Result<i64, PersistError> {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let sql = provider.next_identity_sql(&base.table_name);
        let rows = Self::select(&sql, connection_name)?;
        let id = rows
            .first()
            .and_then(|r| r.values().next())
            .and_then(|v| v.as_i64())
            .unwrap_or_default();
        Ok(id)
    }

    pub fn get_sql(base: &BaseObject, connection_name: &str) -> String {
        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let mut p = BaseObject::new();
        p.set("id", base.get("id"));
        p.set("table", Value::String(provider.format_table_name(&base.table_name)));
        Self::substitute_template(&p, "select * from ^(table) where id=^(id) and is_active=1")
    }

    /// Copy every column from a row into the object's backing map.
    pub fn auto_assign<T: DomainObject>(row: &Row, obj: &mut T) {
        for (k, v) in row {
            obj.base_mut().set(k, v.clone());
        }
    }

    /// Replace `^(key)` tokens in a template with the plain value of each key.
    pub fn substitute_template(params: &BaseObject, sql_template: &str) -> String {
        let mut sql = sql_template.to_string();
        for (k, v) in &params.data {
            sql = sql.replace(&format!("^({})", k), &value_to_plain(v));
        }
        sql
    }

    // ── QUERY CACHE ──────────────────────────────────────────────────────

    pub fn get_query_by_name(
        query_name: &str,
        connection_name: &str,
    ) -> Result<Option<BaseObject>, PersistError> {
        if let Some(cached) = query_cache().lock().unwrap().get(query_name) {
            return Ok(cached.clone());
        }

        let provider = DatabaseProviderFactory::create_provider(connection_name);
        let sql = format!(
            "SELECT s.id, s.name, s.sql_text, s.description, s.created_by, \
             ds.name as data_source_name FROM {} s LEFT JOIN {} ds \
             ON s.data_source_id = ds.id WHERE s.{} = {}",
            provider.format_table_name("core.sql"),
            provider.format_table_name("core.data_source"),
            provider.format_column_name("name"),
            provider.format_value(&Value::String(query_name.to_string())),
        );

        let rows = Self::select(&sql, connection_name)?;
        let result = rows.first().map(|row| {
            let mut q = BaseObject::new();
            for (k, v) in row {
                q.set(k, v.clone());
            }
            q
        });

        query_cache()
            .lock()
            .unwrap()
            .insert(query_name.to_string(), result.clone());
        Ok(result)
    }

    /// Execute a named query (from core.sql) and return raw rows.
    pub fn execute_query_by_name(
        query_name: &str,
        connection_name: &str,
    ) -> Result<Vec<Row>, PersistError> {
        let query = Self::get_query_by_name(query_name, connection_name)?
            .ok_or_else(|| PersistError::Db(format!("Query '{}' not found in core.sql", query_name)))?;
        let sql = value_to_plain(&query.get("sql_text"));
        let data_source = match query.get("data_source_name") {
            Value::String(s) if !s.is_empty() => s,
            _ => connection_name.to_string(),
        };
        Self::select(&sql, &data_source)
    }

    /// Execute a named query and materialise rows into domain objects.
    pub fn execute_query_into<T: DomainObject + Default>(
        query_name: &str,
        connection_name: &str,
    ) -> Result<Vec<T>, PersistError> {
        let rows = Self::execute_query_by_name(query_name, connection_name)?;
        Ok(rows
            .into_iter()
            .map(|row| {
                let mut obj = T::default();
                obj.initialize();
                Self::auto_assign(&row, &mut obj);
                obj
            })
            .collect())
    }

    /// Execute a named query whose SQL contains `^(key)` tokens, substituting
    /// values from `filter`, and return the raw rows.
    pub fn execute_query_rows_filtered(
        query_name: &str,
        filter: &BaseObject,
        connection_name: &str,
    ) -> Result<Vec<Row>, PersistError> {
        let query = Self::get_query_by_name(query_name, connection_name)?
            .ok_or_else(|| PersistError::Db(format!("Query '{}' not found in core.sql", query_name)))?;
        let template = value_to_plain(&query.get("sql_text"));
        let data_source = match query.get("data_source_name") {
            Value::String(s) if !s.is_empty() => s,
            _ => connection_name.to_string(),
        };
        let sql = Self::substitute_template(filter, &template);
        Self::select(&sql, &data_source)
    }

    /// As `execute_query_rows_filtered`, materialised into domain objects.
    pub fn execute_query_into_filtered<T: DomainObject + Default>(
        query_name: &str,
        filter: &BaseObject,
        connection_name: &str,
    ) -> Result<Vec<T>, PersistError> {
        let rows = Self::execute_query_rows_filtered(query_name, filter, connection_name)?;
        Ok(rows
            .into_iter()
            .map(|row| {
                let mut obj = T::default();
                obj.initialize();
                Self::auto_assign(&row, &mut obj);
                obj
            })
            .collect())
    }

    pub fn clear_query_cache() {
        query_cache().lock().unwrap().clear();
    }

    pub fn refresh_query_by_name(query_name: &str) -> Result<Option<BaseObject>, PersistError> {
        query_cache().lock().unwrap().remove(query_name);
        Self::get_query_by_name(query_name, "default")
    }

    pub fn cache_size() -> usize {
        query_cache().lock().unwrap().len()
    }
}

// ── shared helpers ──────────────────────────────────────────────────────

pub(crate) fn json_now() -> Value {
    Value::String(chrono::Utc::now().naive_utc().format("%Y-%m-%dT%H:%M:%S%.f").to_string())
}

pub(crate) fn user_name() -> String {
    std::env::var("USER")
        .or_else(|_| std::env::var("USERNAME"))
        .unwrap_or_else(|_| "unknown".to_string())
}

fn value_to_plain(v: &Value) -> String {
    match v {
        Value::String(s) => s.clone(),
        Value::Null => String::new(),
        other => other.to_string(),
    }
}
